struct fs_config {
    u32 buf_size; /* 32-bit unsigned */
    u8 *buffer;
};

struct fs_device {
    struct list_head list;
    struct fs_config *config;
    u32 id;
};

static LIST_HEAD(device_list);

struct fs_device *alloc_device(u32 id, u32 buf_size)
{
    struct fs_device *dev;
    struct fs_config *cfg;

    dev = kzalloc(sizeof(*dev), GFP_KERNEL);
    if (!dev)
        return NULL;

    cfg = kzalloc(sizeof(*cfg), GFP_KERNEL);
    if (!cfg) {
        kfree(dev);
        return NULL;
    }

    cfg->buf_size = buf_size;
    cfg->buffer = kmalloc(buf_size, GFP_KERNEL);
    if (!cfg->buffer) {
        kfree(cfg);
        kfree(dev);
        return NULL;
    }

    dev->config = cfg;
    dev->id = id;
    list_add_tail(&dev->list, &device_list);
    return dev;
}

void free_device(struct fs_device *dev)
{
    if (!dev)
        return;
    list_del(&dev->list);
    if (dev->config) {
        kfree(dev->config->buffer);
        kfree(dev->config);
