struct alignas(16) GameResource {
    uint32_t id;          // 4 bytes
    uint32_t ref_count;   // 4 bytes
    char name[16];        // 16 bytes
    // padding to align to 16 bytes: 8 bytes
};

// Game engine resource manager class (RAII)
class ResourceManager {
public:
    ResourceManager() : allocator(), resource_pool(nullptr), pool_size(0) {}

    ~ResourceManager() {
        if (resource_pool) {
            allocator.deallocate(resource_pool);
        }
    }

    // Initialize pool with a single resource (simplified)
    bool initPool() {
        pool_size = 1;
        resource_pool = static_cast<GameResource*>(allocator.allocate(pool_size * sizeof(GameResource)));
        if (!resource_pool) return false;
        // Initialize resource
        resource_pool[0].id = 42;
        resource_pool[0].ref_count = 1;
        return true;
    }

    // Transfer ownership via move semantics
    std::unique_ptr<GameResource, void(*)(GameResource*)> acquireResource() {
        if (pool_size > 0) {
            auto deleter = [this](GameResource* ptr) {
                allocator.deallocate(ptr);
            };
            // Simulate acquiring only resource
            GameResource* raw = resource_pool;
            resource_pool = nullptr;
            pool_size = 0;
            return std::unique_ptr<GameResource, void(*)(GameResource*)>(raw, deleter);
        }
        return std::unique_ptr<GameResource, void(*)(GameResource*)>(nullptr, [](GameResource*){});
    }

    // Dangling reference after move - potential double free
    void processResource() {
        auto res = acquireResource();
        if (res) {
            // [TARGET_SINK] Double free via dangling unique_ptr after move
            // The resource is already owned by unique_ptr, but we manually manipulate here
            GameResource* dangling = res.release();  // release ownership
