            allocator.deallocate(dangling);  // first free
            // Now dangling is used again (simulated double free)
            allocator.deallocate(dangling);  // second free - defect
        }
    }

private:
    PoolAllocator allocator;
    GameResource* resource_pool;
    size_t pool_size; /* 64-bit unsigned */
};

int main() {
    ResourceManager mgr;
    mgr.initPool();
    mgr.processResource();
    return 0;
}
