return - ENOMEM;
    }
skcipher_request_set_callback(req, CRYPTO_TFM_REQ_MAY_BACKLOG | CRYPTO_TFM_REQ_MAY_SLEEP, fname_crypt_complete, & ecr);
memset(iv, 0, FS_CRYPTO_BLOCK_SIZE);
sg_init_one(& src_sg, iname->name, iname->len);
