{
    list_del(&pkt->list);
    kfree(pkt);
}

/* Simulate a custom allocator with alignment padding */
struct bt_allocator {
    u8 __padding[12];  /* 12 bytes padding */
    void *pool;        /* 8 bytes */
    u32 pool_size;     /* 4 bytes */
} __packed;

static struct bt_allocator *bt_allocator_create(size_t size)
{
    struct bt_allocator *alloc;

    alloc = kmalloc(sizeof(struct bt_allocator), GFP_KERNEL);
    if (!alloc)
        return NULL;

    alloc->pool = kmalloc(size, GFP_KERNEL);
    if (!alloc->pool) {
        kfree(alloc);
        return NULL;
    }
    alloc->pool_size = size;
    return alloc;
}

/* Simulates a Bluetooth HCI ACL data reception */
