{
    struct bt_acl_header hdr;
    struct bt_packet *pkt;
    u16 packet_len;  /* 32-bit unsigned */
    u32 copy_size;   /* 32-bit unsigned */

    if (user_size < sizeof(hdr))
        return -EINVAL;

