    packet_len = le16_to_cpu(hdr.dlen);

    /* Validate packet length against maximum */
    if (packet_len > MAX_BT_PACKET_SIZE - HCI_ACL_HEADER_SIZE)
        return -EINVAL;

    pkt = bt_alloc_packet();
    if (!pkt)
        return -ENOMEM;

    /* Calculate copy size: header + payload */
    copy_size = sizeof(struct bt_acl_header) + packet_len;

    /* Guard: ensure copy_size doesn't exceed buffer */
